// ============================================
// INJECT ACTIVE SERVICES (COMMERCIAL ONLY: SER & PRO)
// ============================================

const item = $input.first().json;

// Estrazione dati
const honeypotData = item.HoneyPot || {};
const catalogData = item.service_catalog_setup || {};

// Array per asset commerciali attivi
const activeCommercialAssets = [];

// Navigazione catalogo
if (catalogData.categories && Array.isArray(catalogData.categories)) {
    catalogData.categories.forEach(category => {

        // --- FILTRO MACRO ---
        // Accetto solo Servizi (SER) e Prodotti (PRO). Ignoro SOP (Internal).
        const isCommercialMacro = (category.macrocategories === "SER" || category.macrocategories === "PRO");

        if (isCommercialMacro && category.subcategories && Array.isArray(category.subcategories)) {
            category.subcategories.forEach(asset => {

                // --- FILTRO STATO ---
                // Prendo solo quelli pronti (blueprint_ready)
                if (asset.blueprint_ready === true) {
                    activeCommercialAssets.push({
                        macro: category.macrocategories, // Fondamentale per distinguere se è un bene o un servizio
                        category: category.name,
                        category_short: category.short_name,
                        name: asset.name,
                        short_name: asset.short_name,
                        callback_data: asset.callback_data,
                        original_slug: asset.original_slug || null
                    });
                }
            });
        }
    });
}

// Iniezione pulita nell'HoneyPot
honeypotData.active_services = activeCommercialAssets;
honeypotData.active_services_count = activeCommercialAssets.length;

// Output mantenendo l'integrità dell'oggetto originale
return [{
    json: {
        ...item,
        HoneyPot: honeypotData
    }
}];

