const root = $input.first().json;
const hp = root.HoneyPot || {};
const od = root.owner_data || {};
const ai = root.MiniSiteJson || {}; // Mantiene intatta la struttura originale del DB letta dall'Editor
const bot = root.owner_bot || {};

// 1. Mappa i percorsi delle immagini caricate (photo di Honeypot come hero_image)
const assets = {
    logo: hp.assets?.logo?.url || "",
    hero_image: hp.assets?.photo?.url || "", // Foto rappresentativa dell'attività (locali, team o ufficio)
    gallery1: root.content_url?.gallery1 || "",
    gallery2: root.content_url?.gallery2 || "",
    gallery3: root.content_url?.gallery3 || ""
};

// 2. Imposta i colori e mantiene il font originale scelto da Gemini
const brand = {
    primary_color: hp.assets?.logo?.meta?.colors?.[0] || "#212D67",
    font: ai.design?.font || "Plus Jakarta Sans"
};

// 3. Formatta gli orari operativi programmati nell'HoneyPot
const daysMap = { monday: 'monday', tuesday: 'tuesday', wednesday: 'wednesday', thursday: 'thursday', friday: 'friday', saturday: 'saturday', sunday: 'sunday' };
const hours = hp.availability_schedule?.hours || {};
const availability = {};
for (const key in daysMap) {
    const d = hours[key];
    availability[daysMap[key]] = (d && d.morning?.from) ? `${d.morning.from}-${d.afternoon?.to || d.morning.to}` : "Chiuso";
}

// 4. Compila lo schema JSON strutturato conforme al vostro JSON Engine v2.0
const minisite_json = {
    // --- BLOCCO 1: CHIAVI ORIGINALI (Lette e scritte dall'Editor minisite.html) ---
    style: ai.style || "classic",
    path: ai.path || "",
    design: {
        font: ai.design?.font || "Plus Jakarta Sans",
        radius: ai.design?.radius || "24px"
    },
    hero: {
        h1: ai.hero?.h1 || od.ragione_sociale || "", // Letto dall'input dell'editor
        sub: ai.hero?.sub || ""                      // Letto dall'input dell'editor
    },
    seo: {
        title: ai.seo?.title || od.ragione_sociale || "",
        description: ai.seo?.description || od.business_description || "",
        keywords: ai.seo?.keywords || [],
        faq: ai.seo?.faq || []
    },
    sections: {
        about: {
            kicker: ai.sections?.about?.kicker || "Mission",
            headline: ai.sections?.about?.headline || "",
            body: ai.sections?.about?.body || ""
        },
        usp: ai.sections?.usp || [],
        process: ai.sections?.process || [],
        // Servizi mappati programmaticamente
        services: (hp.active_services || []).map(svc => {
            const icon = (svc.short_name && svc.short_name.match(/\p{Emoji}/u)) ? svc.short_name.match(/\p{Emoji}/u)[0] : '⚡';
            const refinedDesc = ai.service_descriptions?.find(d => d.name === svc.name)?.refined_desc || "";
            return {
                title: svc.name,
                description: refinedDesc.substring(0, 120),
                icon: icon
            };
        })
    },
    service_descriptions: ai.service_descriptions || [],

    // --- BLOCCO 2: AGGIUNTE RICHIESTE DALLA PIATTAFORMA (Lette dal PHP) ---
    offer_text: hp.offer_text || "", // <-- INIETTATA NATIVAMENTE NEL COSTRUTTO DEL SITO!
    contact: {
        phone: od.phone || "",
        email: od.email || "",
        address: od.indirizzo || "",
        city: od.indirizzo?.split(',')?.pop()?.trim() || "Palermo"
    },
    assets: assets,
    brand: brand,
    availability: availability,
    owner_bot: {
        first_name: bot.first_name || "",
        username: bot.username || ""
    }
};

// Restituisce l'oggetto combinato contenente la chiave 'assembled_minisite_json'
return [{ json: { ...root, assembled_minisite_json: minisite_json } }];

